// Ancient continent population shares (%) — rough estimates from Maddison / McEvedy
const ANCIENT_CONT_ANCHORS: { year: number; s: Record<string, number> }[] = [
  { year: -10000, s: { Asia: 35,  Africa: 30, Europe: 18, "North America": 8,   "South America": 6,   Oceania: 3   } },
  { year: -5000,  s: { Asia: 40,  Africa: 25, Europe: 20, "North America": 7,   "South America": 6,   Oceania: 2   } },
  { year: 1,      s: { Asia: 71,  Africa: 8,  Europe: 18, "North America": 1.5, "South America": 1,   Oceania: 0.5 } },
  { year: 500,    s: { Asia: 65,  Africa: 10, Europe: 20, "North America": 2.5, "South America": 2,   Oceania: 0.5 } },
  { year: 1000,   s: { Asia: 65,  Africa: 12, Europe: 18, "North America": 2.5, "South America": 2,   Oceania: 0.5 } },
  { year: 1340,   s: { Asia: 60,  Africa: 12, Europe: 24, "North America": 2,   "South America": 1.5, Oceania: 0.5 } },
  { year: 1500,   s: { Asia: 61,  Africa: 11, Europe: 15, "North America": 7,   "South America": 5.5, Oceania: 0.5 } },
  { year: 1700,   s: { Asia: 64,  Africa: 10, Europe: 18, "North America": 4,   "South America": 3.5, Oceania: 0.5 } },
  { year: 1800,   s: { Asia: 65,  Africa: 11, Europe: 20, "North America": 3,   "South America": 1.5, Oceania: 0.5 } },
];

function getAncientContinentShares(year: number): Record<string, number> {
  const a = ANCIENT_CONT_ANCHORS;
  if (year <= a[0].year) return a[0].s;
  if (year >= a[a.length - 1].year) return a[a.length - 1].s;
  for (let i = 0; i < a.length - 1; i++) {
    if (year >= a[i].year && year <= a[i + 1].year) {
      const t = (year - a[i].year) / (a[i + 1].year - a[i].year);
      const result: Record<string, number> = {};
      for (const c of Object.keys(a[i].s)) {
        result[c] = a[i].s[c] + t * ((a[i + 1].s[c] ?? a[i].s[c]) - a[i].s[c]);
      }
      return result;
    }
  }
  return a[a.length - 1].s;
}

function getAncientLargestRegion(year: number): string {
  if (year < -3000) return 'Unknown';
  if (year < -1500) return 'Predynastic Egypt';
  if (year < -500)  return 'Zhou Dynasty China';
  if (year < 220)   return 'Han China / Roman Empire';
  if (year < 600)   return 'Roman / Persian Empire';
  if (year < 900)   return 'Tang China';
  if (year < 1200)  return 'Song China';
  if (year < 1400)  return 'Mongol Empire / Ming China';
  if (year < 1700)  return 'Ming / Qing China';
  return 'Qing China';
}

function getAncientLargestCity(year: number): string {
  if (year < -3000) return 'Uruk';
  if (year < -1500) return 'Memphis';
  if (year < -500)  return 'Babylon';
  if (year < 400)   return 'Rome';
  if (year < 800)   return 'Constantinople';
  if (year < 1000)  return 'Baghdad';
  if (year < 1400)  return 'Hangzhou';
  if (year < 1600)  return 'Nanjing';
  return 'Beijing';
}

function interpolate(data: Record<number, number>, year: number): number {
  const keys = Object.keys(data).map(Number).sort((a, b) => a - b);
  if (year <= keys[0]) return data[keys[0]];
  if (year >= keys[keys.length - 1]) return data[keys[keys.length - 1]];
  for (let i = 0; i < keys.length - 1; i++) {
    if (year >= keys[i] && year <= keys[i + 1]) {
      const t = (year - keys[i]) / (keys[i + 1] - keys[i]);
      return Math.round(data[keys[i]] + t * (data[keys[i + 1]] - data[keys[i]]));
    }
  }
  return 0;
}

function makeCountryPops(basePops: Record<number, number>): Record<number, { medium: number; high: number; low: number }> {
  const result: Record<number, { medium: number; high: number; low: number }> = {};
  for (const year of YEARS) {
    const med = interpolate(basePops, year);
    result[year] = {
      medium: med,
      high: Math.round(med * (year <= 2025 ? 1 : 1 + (year - 2025) * 0.001)),
      low: Math.round(med * (year <= 2025 ? 1 : 1 - (year - 2025) * 0.0008)),
    };
  }
  return result;
}

