export function getCountryPopulation(year: number, variant: "medium" | "high" | "low" = "medium") {
  const normalizedYear = normalizeYear(year);
  return COUNTRIES.map(c => {
    const popData = c.populations[normalizedYear];
    const population = popData ? popData[variant] : 0;
    const density = c.area > 0 ? Math.round((population * 1000) / c.area) : 0;
    const prevYear = normalizedYear > 1950 ? getPrevYear(normalizedYear) : normalizedYear;
    const prevPop = c.populations[prevYear]?.[variant] || population;
    const growthRate = prevPop > 0 && prevYear !== normalizedYear ? ((population - prevPop) / prevPop) * 100 : 0;
    return {
      iso3: c.iso3,
      name: c.name,
      continent: c.continent,
      population,
      populationMillions: Math.round(population / 100) / 10,
      density,
      lat: c.lat,
      lon: c.lon,
      year,
      growthRate: Math.round(growthRate * 100) / 100,
    };
  });
}

export function getCityPopulation(year: number) {
  const normalizedYear = normalizeYear(year);
  const allCities = CITIES.map(c => {
    const population = interpolate(c.populations, normalizedYear);
    return {
      id: c.id,
      name: c.name,
      country: c.country,
      continent: c.continent,
      population,
      populationMillions: Math.round(population / 100) / 10,
      lat: c.lat,
      lon: c.lon,
      year,
      rank: 0,
      urbanizationLevel: getUrbanizationLevel(population),
    };
  });
  allCities.sort((a, b) => b.population - a.population);
  return allCities.map((c, i) => ({ ...c, rank: i + 1 }));
}

export function getCountryTimeseries(name: string, variant: "medium" | "high" | "low" = "medium") {
  const country = COUNTRIES.find(c => c.name.toLowerCase() === name.toLowerCase() || c.iso3.toLowerCase() === name.toLowerCase());
  if (!country) return null;
  return {
    name: country.name,
    type: "country" as const,
    continent: country.continent,
    data: YEARS.map(year => ({
      year,
      population: country.populations[year]?.[variant] || 0,
      populationMillions: Math.round((country.populations[year]?.[variant] || 0) / 100) / 10,
      isProjection: year > 2024,
    })),
  };
}

export function getCityTimeseries(name: string) {
  const city = CITIES.find(c => c.name.toLowerCase() === name.toLowerCase());
  if (!city) return null;
  return {
    name: city.name,
    type: "city" as const,
    continent: city.continent,
    data: YEARS.map(year => ({
      year,
      population: interpolate(city.populations, year),
      populationMillions: Math.round(interpolate(city.populations, year) / 100) / 10,
      isProjection: year > 2024,
    })),
  };
}

export function getWorldSummary(year: number) {
  if (year < 1800) {
    const worldPop = interpolate(ANCIENT_WORLD_POP, year);
    const urbanPercent = getUrbanPercent(year);
    const shares = getAncientContinentShares(year);
    const continents = ["Asia", "Africa", "Europe", "North America", "South America", "Oceania"];
    const continentBreakdown = continents.map(cont => {
      const share = shares[cont] || 0;
      const contPop = Math.round(worldPop * share / 100);
      return {
        continent: cont,
        population: contPop,
        populationMillions: Math.round(contPop / 100) / 10,
        share: Math.round(share * 10) / 10,
      };
    });
    return {
      year,
      worldPopulation: worldPop,
      worldPopulationMillions: Math.round(worldPop / 100) / 10,
      urbanPopulationPercent: Math.round(urbanPercent * 10) / 10,
      largestCountry: getAncientLargestRegion(year),
      largestCity: getAncientLargestCity(year),
      continentBreakdown,
    };
  }

  const normalizedYear = normalizeYear(year);
  const countries = getCountryPopulation(normalizedYear);
  const totalPop = countries.reduce((sum, c) => sum + c.population, 0);
  const cities = getCityPopulation(normalizedYear);
  const largestCountry = [...countries].sort((a, b) => b.population - a.population)[0];
  const largestCity = cities[0];

  const continents = ["Asia", "Africa", "Europe", "North America", "South America", "Oceania"];
  const continentBreakdown = continents.map(cont => {
    const contPop = countries.filter(c => c.continent === cont).reduce((sum, c) => sum + c.population, 0);
    return {
      continent: cont,
      population: contPop,
      populationMillions: Math.round(contPop / 100) / 10,
      share: totalPop > 0 ? Math.round((contPop / totalPop) * 1000) / 10 : 0,
    };
  });

  const urbanPercent = getUrbanPercent(year);

  return {
    year,
    worldPopulation: totalPop,
    worldPopulationMillions: Math.round(totalPop / 100) / 10,
    urbanPopulationPercent: urbanPercent,
    largestCountry: largestCountry?.name || "China",
    largestCity: largestCity?.name || "Tokyo",
    continentBreakdown,
  };
}

function normalizeYear(year: number): number {
  const closest = YEARS.reduce((prev, curr) => Math.abs(curr - year) < Math.abs(prev - year) ? curr : prev);
  return closest;
}

function getPrevYear(year: number): number {
  const idx = YEARS.indexOf(year);
  return idx > 0 ? YEARS[idx - 1] : year;
}

function getUrbanizationLevel(population: number): "megacity" | "large" | "medium" | "small" {
  if (population >= 10000) return "megacity";
  if (population >= 5000) return "large";
  if (population >= 1000) return "medium";
  return "small";
}

function getUrbanPercent(year: number): number {
  const urbanData: Record<number, number> = {
    [-10000]: 0,
    [-5000]:  0.05,
    [-3000]:  0.1,
    [-1000]:  0.8,
    [1]:      2.0,
    [500]:    1.5,
    [1000]:   2.0,
    [1500]:   3.0,
    [1700]:   5.0,
    [1800]:   7.0,
    [1900]:   13.0,
    1950: 29.6, 1960: 33.6, 1970: 36.6, 1980: 39.4, 1990: 43.0, 2000: 46.7, 2010: 51.6, 2020: 56.2, 2025: 57.5, 2030: 60.4, 2040: 63.8, 2050: 68.4, 2060: 72.0, 2070: 74.8, 2080: 77.0, 2090: 79.0, 2100: 80.0,
  };
  return interpolate(urbanData, year);
}
